fn file_upload_set_files_advances_id_counter_past_external_ids() {
    let mut service = Service::<Machine>::new(
        Props::new().id("upload").multiple(true),
        &Env::default(),
        &Messages::default(),
    );

    drop(service.send(Event::SetFiles(Some(vec![item(
        "file-1",
