            .apply(|ctx| {
                ctx.drag_counter = 0;
                ctx.dragging = false;
            })
            .with_named_effect("announce-dropzone-left", |ctx, _props, _send| {
                use_platform_effects().announce(&(ctx.messages.drop_zone_left)(&ctx.locale));
                no_cleanup()
            }))
    } else {
        Some(TransitionPlan::context_only(move |ctx| {
            ctx.drag_counter = new_counter;
        }))
    }
}

