pub fn item_delete_trigger_attrs(&self, index: usize) -> AttrMap {
    let mut attrs = AttrMap::new();
    let [(scope_attr, scope_val), (part_attr, part_val)] =
        Part::ItemDeleteTrigger { index }.data_attrs();
    attrs.set(scope_attr, scope_val);
