/// the [`Effect::FilesChanged`] callback on set changes).
fn commit_files(context: &mut Context, files: Vec<Item>) {
    if context.files.is_controlled() {
        context.files.sync_controlled(Some(files.clone()));
    }

    context.files.set(files);
}

