    const KB: f64 = 1_024.0;
    const MB: f64 = KB * 1_024.0;
    let bytes_f = bytes as f64;

    let (value, suffix) = if bytes_f >= MB {
        (bytes_f / MB, "MB")
    } else if bytes_f >= KB {
        (bytes_f / KB, "KB")
    } else {
        (bytes_f, "bytes")
    };

    let max_fraction_digits = if suffix == "bytes" || value.fract() == 0.0 {
        0
    } else {
        1
    };

